import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { 
  Clock, 
  CheckCircle, 
  AlertCircle, 
  MapPin, 
  Calendar, 
  User,
  ArrowLeft,
  Download,
  Trash2,
  Camera,
  Edit,
  Settings,
  UserPlus,
  Zap,
  Tag
} from 'lucide-react';
import toast from 'react-hot-toast';

const ComplaintDetail = () => {
  const { id } = useParams();
  const { api, user } = useAuth();
  const navigate = useNavigate();
  const [complaint, setComplaint] = useState(null);
  const [evidences, setEvidences] = useState([]);
  const [loading, setLoading] = useState(true);
  const [updatingStatus, setUpdatingStatus] = useState(false);

  const isAdmin = user?.role === 'ADMIN' || user?.role === 'OWNER';

  useEffect(() => {
    fetchComplaint();
  }, [id]);

  const handleStatusUpdate = async (newStatus) => {
    try {
      setUpdatingStatus(true);
      await api.put(`/complaints/${id}/status`, { status: newStatus });
      toast.success(`Status updated to ${newStatus.replace('_', ' ')}`);
      fetchComplaint(); // Refresh
    } catch (error) {
      console.error('Error updating status:', error);
      toast.error('Failed to update status');
    } finally {
      setUpdatingStatus(false);
    }
  };

  const fetchComplaint = async () => {
    try {
      console.log('Fetching complaint with ID:', id);
      console.log('Making request to:', `/complaints/${id}`);
      const response = await api.get(`/complaints/${id}`);
      console.log('Complaint response:', response);
      console.log('Complaint data:', response.data);
      setComplaint(response.data);

      // Skip evidence fetch for now to isolate the issue
      // const evidenceResponse = await api.get(`/files/complaint/${id}`);
      // setEvidences(evidenceResponse.data || []);
    } catch (error) {
      console.error('Error fetching complaint:', error);
      console.error('Error response:', error.response);
      console.error('Error status:', error.response?.status);
      console.error('Error data:', error.response?.data);
      toast.error('Failed to load complaint details');
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'PENDING':
        return <Clock className="h-5 w-5 text-yellow-600" />;
      case 'IN_PROGRESS':
        return <AlertCircle className="h-5 w-5 text-blue-600" />;
      case 'RESOLVED':
        return <CheckCircle className="h-5 w-5 text-green-600" />;
      default:
        return <Clock className="h-5 w-5 text-gray-600" />;
    }
  };

  const getStatusClass = (status) => {
    switch (status) {
      case 'PENDING':
        return 'bg-yellow-100 text-yellow-800';
      case 'IN_PROGRESS':
        return 'bg-blue-100 text-blue-800';
      case 'RESOLVED':
        return 'bg-green-100 text-green-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getPriorityClass = (priority) => {
    switch (priority) {
      case 'LOW':
        return 'bg-gray-100 text-gray-800';
      case 'MEDIUM':
        return 'bg-orange-100 text-orange-800';
      case 'HIGH':
        return 'bg-red-100 text-red-800';
      case 'URGENT':
        return 'bg-purple-100 text-purple-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const downloadFile = async (evidence) => {
    try {
      const response = await api.get(`/files/download/${evidence.filePath.split('/').pop()}`, {
        responseType: 'blob'
      });

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.download = evidence.fileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Error downloading file:', error);
      toast.error('Failed to download file');
    }
  };

  const deleteEvidence = async (evidenceId) => {
    if (!window.confirm('Are you sure you want to delete this evidence?')) {
      return;
    }

    try {
      await api.delete(`/files/${evidenceId}`);
      setEvidences(evidences.filter(e => e.id !== evidenceId));
      toast.success('Evidence deleted successfully');
    } catch (error) {
      console.error('Error deleting evidence:', error);
      toast.error('Failed to delete evidence');
    }
  };

  const deleteComplaint = async () => {
    if (!window.confirm('Are you sure you want to delete this complaint? This action cannot be undone.')) {
      return;
    }

    try {
      await api.delete(`/complaints/${id}`);
      toast.success('Complaint deleted successfully');
      navigate('/complaints');
    } catch (error) {
      console.error('Error deleting complaint:', error);
      toast.error('Failed to delete complaint');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!complaint) {
    return (
      <div className="text-center py-8">
        <p className="text-gray-500">Complaint not found</p>
      </div>
    );
  }

  return (
    <div className="p-6">
      {/* Header Section */}
      <div className="bg-gradient-to-r from-primary-600 to-primary-700 rounded-xl p-8 text-white flex flex-col sm:flex-row sm:items-center justify-between gap-6 overflow-hidden relative shadow-lg mb-6">
        <div className="relative z-10">
          <button
            onClick={() => navigate(-1)}
            className="inline-flex items-center text-primary-100 hover:text-white transition-colors mb-4 group"
          >
            <ArrowLeft className="h-5 w-5 mr-2 group-hover:-translate-x-1 transition-transform" />
            Back to Complaints
          </button>
          <h1 className="text-3xl font-bold mb-2">Complaint Details</h1>
          <p className="text-primary-100">View and manage complaint information</p>
        </div>
        <div className="relative z-10 flex items-center space-x-3">
          <span className={`inline-flex items-center px-4 py-2 rounded-full text-sm font-bold bg-white/20 backdrop-blur-sm`}>
            {getStatusIcon(complaint.status)}
            <span className="ml-2">{complaint.status.replace('_', ' ')}</span>
          </span>
        </div>
      </div>

      {/* Side-by-Side Layout */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Side - Complaint Details (2 columns) */}
        <div className="lg:col-span-2 space-y-6">
          {/* Main Content Card */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="p-6">
              {/* Title and Edit Button */}
              <div className="flex items-start justify-between mb-6 pb-6 border-b border-gray-200">
                <div className="flex-1">
                  <h2 className="text-xl font-semibold text-gray-900 mb-3">{complaint.title}</h2>
                  <div className="flex items-center space-x-3">
                    <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-medium ${getStatusClass(complaint.status)}`}>
                      {getStatusIcon(complaint.status)}
                      <span className="ml-1">{complaint.status.toLowerCase().replace('_', ' ')}</span>
                    </span>
                    <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-medium ${getPriorityClass(complaint.priority)}`}>
                      {complaint.priority.toLowerCase()}
                    </span>
                  </div>
                </div>
                <Link
                  to={`/complaints/${id}/edit`}
                  className="inline-flex items-center px-4 py-2 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-primary-600 hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                >
                  <Edit className="h-4 w-4 mr-2" />
                  Edit
                </Link>
              </div>

              {/* Description */}
              <div className="mb-6">
                <h3 className="text-lg font-medium text-gray-900 mb-3">Description</h3>
                <div className="bg-gray-50 rounded-lg p-4">
                  <p className="text-gray-700 whitespace-pre-wrap">{complaint.description}</p>
                </div>
              </div>

              {/* Location Information */}
              <div className="mb-6">
                <h3 className="text-lg font-medium text-gray-900 mb-3">Location</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {complaint.blockNumber && (
                    <div className="bg-gray-50 rounded-lg p-4">
                      <div className="flex items-center space-x-2">
                        <MapPin className="h-4 w-4 text-gray-400" />
                        <div>
                          <p className="text-sm text-gray-500">Block</p>
                          <p className="font-medium text-gray-900">{complaint.blockNumber}</p>
                        </div>
                      </div>
                    </div>
                  )}
                  {complaint.buildingNumber && (
                    <div className="bg-gray-50 rounded-lg p-4">
                      <div className="flex items-center space-x-2">
                        <MapPin className="h-4 w-4 text-gray-400" />
                        <div>
                          <p className="text-sm text-gray-500">Building</p>
                          <p className="font-medium text-gray-900">{complaint.buildingNumber}</p>
                        </div>
                      </div>
                    </div>
                  )}
                  {complaint.roomNumber && (
                    <div className="bg-gray-50 rounded-lg p-4">
                      <div className="flex items-center space-x-2">
                        <MapPin className="h-4 w-4 text-gray-400" />
                        <div>
                          <p className="text-sm text-gray-500">Room</p>
                          <p className="font-medium text-gray-900">{complaint.roomNumber}</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Metadata */}
              <div className="border-t border-gray-200 pt-6">
                <h3 className="text-lg font-medium text-gray-900 mb-3">Details</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <User className="h-4 w-4 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-500">Reported by</p>
                        <p className="font-medium text-gray-900">{complaint.userName}</p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <Calendar className="h-4 w-4 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-500">Reported on</p>
                        <p className="font-medium text-gray-900">
                          {new Date(complaint.createdAt).toLocaleDateString()}
                        </p>
                      </div>
                    </div>
                  </div>
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center space-x-2">
                      <Tag className="h-4 w-4 text-gray-400" />
                      <div>
                        <p className="text-sm text-gray-500">Category</p>
                        <p className="font-medium text-gray-900">{complaint.assetCategory?.replace('_', ' ') || 'OTHER'}</p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Evidence Section */}
          {evidences.length > 0 && (
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
              <h3 className="text-lg font-medium text-gray-900 mb-4 flex items-center">
                <Camera className="h-5 w-5 mr-2 text-gray-400" />
                Evidence & Attachments ({evidences.length})
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {evidences.map((evidence) => (
                  <div key={evidence.id} className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
                    <div className="flex items-center space-x-2 mb-3">
                      <Camera className="h-4 w-4 text-gray-400" />
                      <span className="text-sm font-medium text-gray-700 truncate">{evidence.fileName}</span>
                    </div>
                    <div className="text-xs text-gray-500 mb-3">
                      {(evidence.fileSize / 1024 / 1024).toFixed(2)} MB
                    </div>
                    <div className="flex space-x-2">
                      <button
                        onClick={() => downloadFile(evidence)}
                        className="flex-1 inline-flex items-center justify-center px-3 py-2 border border-gray-300 shadow-sm text-xs font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                      >
                        <Download className="h-3 w-3 mr-1" />
                        Download
                      </button>
                      <button
                        onClick={() => deleteEvidence(evidence.id)}
                        className="flex-1 inline-flex items-center justify-center px-3 py-2 border border-transparent text-xs font-medium rounded-md text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                      >
                        <Trash2 className="h-3 w-3 mr-1" />
                        Delete
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Right Side - Admin Console (1 column, sticky) */}
        {isAdmin && (
          <div className="lg:col-span-1">
            <div className="sticky top-6 space-y-6">
              {/* Admin Console Card */}
              <div className="bg-white rounded-xl shadow-lg border border-gray-200 p-6">
                <div className="flex items-center space-x-2 mb-6 pb-4 border-b border-gray-200">
                  <Settings className="h-6 w-6 text-primary-600" />
                  <h3 className="text-xl font-bold text-gray-900">Admin Console</h3>
                </div>

                {/* Status Management */}
                <div className="mb-6">
                  <div className="flex items-center space-x-2 mb-4">
                    <Zap className="h-5 w-5 text-yellow-600" />
                    <h4 className="font-bold text-gray-900">Quick Status Update</h4>
                  </div>
                  <div className="space-y-2">
                    {['PENDING', 'IN_PROGRESS', 'RESOLVED', 'REJECTED'].map((status) => (
                      <button
                        key={status}
                        disabled={updatingStatus || complaint.status === status}
                        onClick={() => handleStatusUpdate(status)}
                        className={`w-full px-4 py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-between ${
                          complaint.status === status
                            ? 'bg-primary-600 text-white shadow-lg'
                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        <span>{status.replace('_', ' ')}</span>
                        {complaint.status === status && <CheckCircle className="h-4 w-4" />}
                        {updatingStatus && complaint.status === status && <span className="animate-pulse">...</span>}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Quick Actions */}
                <div className="border-t border-gray-200 pt-6">
                  <h4 className="font-bold text-gray-900 mb-4">Quick Actions</h4>
                  <div className="space-y-2">
                    <Link
                      to={`/complaints/${id}/edit`}
                      className="w-full inline-flex items-center justify-center px-4 py-3 border border-gray-300 rounded-xl text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                    >
                      <Edit className="h-4 w-4 mr-2" />
                      Edit Complaint
                    </Link>
                    <button
                      onClick={() => deleteComplaint()}
                      className="w-full inline-flex items-center justify-center px-4 py-3 border border-transparent text-sm font-medium rounded-xl text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                    >
                      <Trash2 className="h-4 w-4 mr-2" />
                      Delete Complaint
                    </button>
                  </div>
                </div>
              </div>

              {/* Complaint Info Summary */}
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
                <h4 className="font-bold text-gray-900 mb-4">Complaint Info</h4>
                <div className="space-y-3 text-sm">
                  <div className="flex justify-between">
                    <span className="text-gray-500">ID:</span>
                    <span className="font-medium text-gray-900">#{complaint.id}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Status:</span>
                    <span className={`font-medium ${complaint.status === 'RESOLVED' ? 'text-green-600' : complaint.status === 'PENDING' ? 'text-yellow-600' : 'text-blue-600'}`}>
                      {complaint.status.replace('_', ' ')}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Priority:</span>
                    <span className={`font-medium ${complaint.priority === 'URGENT' ? 'text-red-600' : complaint.priority === 'HIGH' ? 'text-orange-600' : 'text-gray-600'}`}>
                      {complaint.priority}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Created:</span>
                    <span className="font-medium text-gray-900">
                      {new Date(complaint.createdAt).toLocaleDateString()}
                    </span>
                  </div>
                  {complaint.resolvedAt && (
                    <div className="flex justify-between">
                      <span className="text-gray-500">Resolved:</span>
                      <span className="font-medium text-green-600">
                        {new Date(complaint.resolvedAt).toLocaleDateString()}
                      </span>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ComplaintDetail;
